public class Main {
    public static void main(String[] args) {

        int     age           = 30;
        double  monthlyIncome = 45000.0;
        boolean hasLoan       = false;
        String  creditRating  = "Good";

        // All conditions must be true
        boolean ageOk    = age >= 21 && age <= 60;
        boolean incomeOk = monthlyIncome >= 25000.0;
        boolean loanOk   = !hasLoan;  // no existing loan
        boolean creditOk = creditRating.equals("Good")
                        || creditRating.equals("Excellent");

        System.out.println("Age check    : " + ageOk);
        System.out.println("Income check : " + incomeOk);
        System.out.println("No loan      : " + loanOk);
        System.out.println("Credit check : " + creditOk);

        if (ageOk && incomeOk && loanOk && creditOk) {
            System.out.println("Result: ELIGIBLE for loan");
        } else {
            System.out.println("Result: NOT eligible");
        }

        // Short-circuit example: name is checked before length
        String name = null;
        if (name != null && name.length() > 0) {
            System.out.println("Name: " + name);
        } else {
            System.out.println("No name provided.");
        }
    }
}

