public class Main {
    public static void main(String[] args) {
        int     age              = 16;
        boolean hasParentConsent = true;
        String  membershipType   = "free";

        boolean isAgeValid = age >= 13;
        boolean canAccess  = isAgeValid && (age >= 18 || hasParentConsent);
        boolean isPremium  = membershipType.equals("premium");

        System.out.println("isAgeValid : " + isAgeValid);
        System.out.println("canAccess  : " + canAccess);
        System.out.println("isPremium  : " + isPremium);

        if (canAccess) {
            System.out.println("Access granted.");
        } else {
            System.out.println("Access denied.");
        }
    }
}
